```typescript
import * as pulumi from "@pulumi/pulumi";
import * as inwx from "@wombelix/pulumi-inwx";

const exampleCom = new inwx.DnssecKey("exampleCom", {
    algorithm: "SHA256",
    domain: "example.com",
    publicKey: "ac12c2...",
});
```
